export const findVariables = (stringLiteral: string) => {
  //1) detect ${name} syntax with a regex

  const matches = stringLiteral.match(/\$\{(.*?)\}/g);
  if (!matches) {
    return [];
  }

  //2) replace each variable with its stringvalue in the row
  const variables = Array.from(matches.entries()).map(([_, match]) => {
    const variable = match.slice(2).slice(0, match.length - 3);
    return variable;
  });

  return variables;
};

export const replaceVariables = (
  stringLiteral: string,
  row: { [key: string]: any },
) => {
  findVariables(stringLiteral).map((variable) => {
    const value = row[variable];
    const string =
      typeof value === "string" ||
      typeof value === "boolean" ||
      typeof value === "number"
        ? String(value)
        : tryJsonStringify(value) || String(value);
    stringLiteral = stringLiteral.replace("${" + variable + "}", string);
  });

  return stringLiteral;
};

export const isExecuteRequired = (
  row: O | undefined,
  propertyKey: string,
  mode: "recalculate" | "only-empty",
  propertyDependencies?: string[],
  isVerticalExpandEnabled?: boolean,
  condition?: string,
) => {
  if (!row) {
    return false;
    //No row found
  }

  const shouldRun =
    condition !== undefined && condition?.trim() !== ""
      ? replaceVariables(condition, row).trim() === "true"
      : true;

  if (!shouldRun) {
    console.log("condition not met", condition);
    return false;
  }

  const currentValue = row[propertyKey];

  if (
    isVerticalExpandEnabled &&
    currentValue !== null &&
    currentValue !== undefined
  ) {
    // NB: in case vertical expand is enabled, should only be ran if it's empty as it causes many new rows
    return false;
  }

  if (
    currentValue !== null &&
    currentValue !== undefined &&
    mode === "only-empty"
  ) {
    //already something while mode "only-empty is set"
    return false;
  }

  const hasPropertyDependencies = propertyDependencies?.map((key) => {
    const hasValue =
      row[key] !== null &&
      row[key] !== undefined &&
      /** This is a shitty little hack for now. If a variable resolves to false, it will stop execution */
      row[key] !== false;
    // console.log(`isExecuteRequired`, propertyKey, `value of ${key}`, row[key], {
    //   hasValue,
    // });

    return hasValue;
  });
  const hasAllDependencies = !hasPropertyDependencies
    ? true
    : isAllTrue(hasPropertyDependencies);

  // console.log({ hasPropertyDependencies, hasAllDependencies });

  if (!hasAllDependencies) {
    //Not all property dependencies are present
    return false;
  }

  return true;
};

export const getValidJsonArrayFile = (json: Json | JsonArray) => {
  const isValid = !!(
    json &&
    typeof json === "object" &&
    !Array.isArray(json) &&
    json?.items &&
    json?.$schema &&
    typeof json?.$schema === "string" &&
    Array.isArray(json.items)
  );

  if (!isValid) {
    return;
  }
  return json as unknown as JsonArray;
};

export const getArrayCapableJsonSchema = (
  schema: CapableJsonSchema | null | undefined,
): CapableJsonSchema | undefined => {
  return schema?.properties?.items as CapableJsonSchema;
};

